function resetLotteryBatch() public onlyWhitelistAdmin {
        require(rewardExecutedOffset == rewardUsersTotalLength, "Reward not completed yet.");
        require(resetLotteryOffset < users.length || users.length == 0, "Lottery already reset.");
        uint resetNumber = 0;
        if (users.length > RESET_LOTTERY_BATCH_SIZE + resetLotteryOffset) {
            resetNumber = RESET_LOTTERY_BATCH_SIZE;
        } else {
            resetNumber = users.length - resetLotteryOffset;
        }

        for (uint index = resetLotteryOffset; index < resetNumber; index++) {
            address userAddress = users[index];
            Bet[] storage bets = userBets[userAddress];
            bets.length = 0;

            userAddressDict[users[index]] = false;
            userWinningStages[users[index]].length = 0;
        }

        resetLotteryOffset += resetNumber;

        // Reset other variables
        if (resetLotteryOffset == users.length) {
            resetLotteryOffset = 0;
            users.length = 0;

             // reset LuckyNumberOpenedNum
            LuckyNumberOpenedNum = 0;

            // reset winningStageSetFlag
            winningStageSetFlag = false;

            // reset SpecialNumbersCandidate
            resetLuckySpecialNumbersCandidate();

            // reset currentRewardVolumn, rewardTotalVolumn
            currentRewardVolumn = 0;
            rewardTotalVolumn = 0;

            // reset totalBetNum
            totalBetNum = 0;

            rewardUsers.length = 0;
            rewardExecutedOffset = 0;
            rewardUsersTotalLength = 0;
            countWinningStageUserOffset = 0;
            countWinningStageUserBetOffset = 0;
            countRewardFirstUserOffset = 0;
            countRewardFirstUserBetOffset = 0;
            countRewardSecondUserOffset = 0;
            countRewardSecondUserBetOffset = 0;

            totalPriceOfFiveToSeven = 0;
            totalPriceOfEight = 0;
            firstStageNumber = 0;
            secondStageNumber = 0;
            thirdStageNumber = 0;
            fourthStageNumber = 0;
            eightStageNumber = 0;

            // set status open
            status = LotteryStatus.Opened;

        }
    }

function getInfo() public view returns(BaseInfo memory, PoolInfo[] memory) {
        BaseInfo memory info;
        info.BONUS_MULTIPLIER = masterChef.BONUS_MULTIPLIER();
        info.bonusEndBlock = masterChef.bonusEndBlock();
        info.devaddr = masterChef.devaddr();
        info.migrator = masterChef.migrator();
        info.owner = masterChef.owner();
        info.startBlock = masterChef.startBlock();
        info.sushi = masterChef.sushi();
        info.sushiPerBlock = masterChef.sushiPerBlock();
        info.totalAllocPoint = masterChef.totalAllocPoint();
        
        info.sushiTotalSupply = IERC20(info.sushi).totalSupply();
        info.sushiOwner = IERC20(info.sushi).owner();

        uint256 poolLength = masterChef.poolLength();
        PoolInfo[] memory pools = new PoolInfo[](poolLength);
        for (uint256 i = 0; i < poolLength; i++) {
            (address lpToken, uint256 allocPoint, uint256 lastRewardBlock, uint256 accSushiPerShare) = masterChef.poolInfo(i);
            IUniswapPair uniV2 = IUniswapPair(lpToken);
            pools[i].lpToken = uniV2;
            pools[i].allocPoint = allocPoint;
            pools[i].lastRewardBlock = lastRewardBlock;
            pools[i].accSushiPerShare = accSushiPerShare;
            
            IERC20 token0 = IERC20(uniV2.token0());
            pools[i].token0 = token0;
            IERC20 token1 = IERC20(uniV2.token1());
            pools[i].token1 = token1;
            
            pools[i].token0name = token0.name();
            pools[i].token0symbol = token0.symbol();
            pools[i].token0decimals = token0.decimals();
            
            pools[i].token1name = token1.name();
            pools[i].token1symbol = token1.symbol();
            pools[i].token1decimals = token1.decimals();
            
            pools[i].logo = names.logos(i);
            pools[i].name = names.names(i);
        }
        return (info, pools);
    }

