function queryStakesOfOwner(address _ownerAccount) external view returns (uint256[] memory, uint256[] memory, uint256[] memory, uint256[] memory, uint256[] memory, bool[] memory) {
        // sender is querying their own account, or owner is querying stakes
        require(msg.sender==_ownerAccount || msg.sender==getOwner(), "You dont have permission");

        // create arrays to return results
        uint256[] memory startDate_r = new uint256[](stakesOfOwner[_ownerAccount].length);
    	uint256[] memory amount_r = new uint256[](stakesOfOwner[_ownerAccount].length);
    	uint256[] memory interest_r = new uint256[](stakesOfOwner[_ownerAccount].length);
    	uint256[] memory penalty_r = new uint256[](stakesOfOwner[_ownerAccount].length);
    	uint256[] memory finishedDate_r = new uint256[](stakesOfOwner[_ownerAccount].length);
    	bool[] memory closed_r = new bool[](stakesOfOwner[_ownerAccount].length);

        // loop the stakes and store them in the array of results
        for(uint256 i=0; i<stakesOfOwner[_ownerAccount].length; i++){
            startDate_r[i] = stakesOfOwner[_ownerAccount][i].startDate;
            amount_r[i] = stakesOfOwner[_ownerAccount][i].amount;
            
            // if the stake is closed return the interest, otherwise calculate it in real time
            if(stakesOfOwner[_ownerAccount][i].closed == true){
                interest_r[i] = stakesOfOwner[_ownerAccount][i].interest;
            }else{
                // calculate interest
                interest_r[i] = calculateInterest(_ownerAccount, i);
            }
            
            penalty_r[i] = stakesOfOwner[_ownerAccount][i].penalty;
            finishedDate_r[i] = stakesOfOwner[_ownerAccount][i].finishedDate;
            closed_r[i] = stakesOfOwner[_ownerAccount][i].closed;
        }
    	return (startDate_r, amount_r, interest_r, penalty_r, finishedDate_r, closed_r);
    }

