function initializePresale(
      uint256 _tokensForPresale,
      uint256 _startDate,
      uint256 _endDate,
      uint256 _minCommitment,
      uint256 _maxCommitment,
      uint256 _softCap,
      uint256 _hardCap,
      uint256 _pricePresale
    ) external onlyOwner {
      require(isInitialized == false, "WIDPresale: Presale has already been initialized.");
      require(_softCap < _hardCap, "WIDPresale: softCap cannot be higher then hardCap");
      require(_startDate < _endDate, "WIDPresale: startDate cannot be after endDate");
      require(_endDate > block.timestamp, "WIDPresale: endDate must be in the future");
      require(_minCommitment < _maxCommitment, "WIDPresale: minCommitment cannot be higher then maxCommitment");
    
      tokensForPresale =_tokensForPresale;
      startDate     = _startDate;
      endDate       = _endDate;
      minCommitment = _minCommitment;
      maxCommitment = _maxCommitment;
      softCap       = _softCap;
      hardCap       = _hardCap;
      pricePresale  = _pricePresale;

      isInitialized = true;
      
      widToken.mintAll(address(this));
      tokensForAdmin = widToken.balanceOf(address(this)).sub(_tokensForPresale);

      emit PresaleInitialized(startDate, endDate);
    }

function withdraw(uint256 _pid) public nonReentrant {
		uint256 countPool = poolList.length;
		require(_pid < countPool, "Not a valid Pool");
		
		_updatePool(_pid);
		
		UserList storage user = userList[_pid][msg.sender];
		PoolList storage pool = poolList[_pid];	
				
		require(user.stakingAmount > 0, "not have withdrawn balance");
		
		user.pendingReward = pendingRewardsFromPool(_pid,msg.sender);
						
		if(user.pendingReward > 0){
			pool.tokenReward.safeTransfer(msg.sender, user.pendingReward );
			
			pool.rewardRemains -= user.pendingReward;
			pool.totalPendingReward -= user.pendingReward;
			user.claimReward += user.pendingReward;
			user.pendingReward -= user.pendingReward;
			
			emit ClaimReward(msg.sender, address(pool.tokenReward) ,user.pendingReward );
		}
				
		pool.lptoken.safeTransfer(msg.sender, user.stakingAmount);
		
		emit Withdraw(msg.sender, address(pool.lptoken) ,user.stakingAmount);
		
		
		pool.lptotal -= user.stakingAmount;
		user.stakingAmount = 0;		
		user.blockStart = block.number;
		
		pool.totalusers -= 1;
		for(uint256 i = 0; i < pooldatas[_pid].length; i++) {
			if(pooldatas[_pid][i] == msg.sender){
				delete pooldatas[_pid][i];
				i = pooldatas[_pid].length;
			}
		}
	}

function processGuildKickProposal(uint256 proposalIndex) external nonReentrant {
        _validateProposalForProcessing(proposalIndex);
        uint256 proposalId = proposalQueue[proposalIndex];
        Proposal storage proposal = proposals[proposalId];
        require(proposal.flags[5] == 1, "!kick");
        proposal.flags[1] = 1; // processed

        bool didPass = _didPass(proposalIndex);
        if (didPass) {
            proposal.flags[2] = 1; // didPass
            Member storage member = members[proposal.applicant];
            member.jailed = proposalIndex;
            // transfer shares to loot
            member.loot = member.loot.add(member.shares);
            totalShares = totalShares.sub(member.shares);
            totalLoot = totalLoot.add(member.shares);
            member.shares = 0; // revoke all shares
        }

        proposedToKick[proposal.applicant] = false;

        _returnDeposit(proposal.sponsor);
        
        emit ProcessGuildKickProposal(proposalIndex, proposalId, didPass);
    }

function processGuildKickProposal(uint256 proposalIndex) public nonReentrant {
        _validateProposalForProcessing(proposalIndex);

        uint256 proposalId = proposalQueue[proposalIndex];
